export default function SpaceCard({ space, onToggleFavorite, isFavorite, commuteMins }) {
  return (
    <a href={`/spaces/${space.id}`} className="group relative block bg-white border-2 border-slate-200 hover:border-sky-400 transition-all duration-300 overflow-hidden">
      {/* Unique Card Shape - Diagonal Cut Top */}
      <div className="absolute top-0 right-0 w-0 h-0 border-l-[60px] border-l-transparent border-t-[60px] border-t-sky-400 opacity-0 group-hover:opacity-100 transition-opacity"></div>
      
      {/* Image Section */}
      <div className="relative h-56 bg-gradient-to-br from-indigo-900 to-blue-900 overflow-hidden">
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent"></div>
        
        {/* Rating Badge - Unique Position */}
        <div className="absolute top-4 left-4">
          <div className="px-3 py-1.5 bg-white rounded-lg shadow-lg flex items-center gap-1">
            <svg className="w-4 h-4 text-rose-500 fill-current" viewBox="0 0 20 20">
              <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
            </svg>
            <span className="text-sm font-black text-slate-900">{space.rating}</span>
          </div>
        </div>
        
        {/* Price Badge - Bottom Right */}
        <div className="absolute bottom-4 right-4">
          <div className="px-4 py-2 bg-gradient-to-br from-sky-500 to-blue-600 rounded-lg shadow-lg">
            <div className="text-white font-black text-xl">₹{space.pricePerDay}</div>
            <div className="text-sky-100 text-xs font-semibold">/day</div>
          </div>
        </div>
      </div>
      
      {/* Content Section */}
      <div className="p-6">
        <h3 className="text-xl font-black text-slate-900 mb-2 group-hover:text-sky-600 transition line-clamp-1">{space.name}</h3>
        
        <div className="flex items-center gap-2 text-sm text-slate-600 mb-4">
          <svg className="w-4 h-4 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
          </svg>
          <span className="line-clamp-1">{space.locationText}</span>
        </div>
        
        {typeof commuteMins === 'number' && (
          <div className="mb-4 inline-flex items-center gap-2 px-3 py-1.5 bg-rose-50 border border-rose-200 rounded-lg">
            <svg className="w-4 h-4 text-rose-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
            <span className="text-xs font-bold text-rose-700">~{commuteMins} min</span>
          </div>
        )}
        
        <div className="flex flex-wrap gap-2 mb-4">
          {space.amenities.slice(0, 2).map((a) => (
            <span key={a} className="text-xs px-3 py-1 bg-slate-100 text-slate-700 font-bold rounded-lg border border-slate-200">{a}</span>
          ))}
          {space.amenities.length > 2 && (
            <span className="text-xs px-3 py-1 bg-sky-50 text-sky-700 font-bold rounded-lg border border-sky-200">+{space.amenities.length - 2}</span>
          )}
        </div>
        
        {onToggleFavorite && (
          <button
            type="button"
            className={`w-full py-3 rounded-xl font-bold transition-all duration-200 flex items-center justify-center gap-2 ${isFavorite ? 'bg-gradient-to-r from-sky-500 to-blue-600 text-white hover:from-sky-600 hover:to-blue-700' : 'bg-slate-100 text-slate-700 hover:bg-slate-200'}`}
            onClick={(e) => {
              e.preventDefault();
              onToggleFavorite(space.id);
            }}
          >
            {isFavorite ? (
              <>
                <svg className="w-5 h-5 fill-current" viewBox="0 0 20 20">
                  <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                </svg>
                Saved
              </>
            ) : (
              <>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.915c.969 0 1.371 1.24.588 1.81l-3.976 2.888a1 1 0 00-.363 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.976-2.888a1 1 0 00-1.176 0l-3.976 2.888c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.363-1.118l-3.976-2.888c-.784-.57-.38-1.81.588-1.81h4.914a1 1 0 00.951-.69l1.519-4.674z" />
                </svg>
                Save
              </>
            )}
          </button>
        )}
      </div>
    </a>
  );
}
